<script setup lang="ts">
defineProps<{ signingIn?: boolean; authError?: string }>()
const emit = defineEmits<{ signIn: [admission: { mode: 'member' | 'referral'; grantToken?: string }] }>()
const open = ref(false), code = ref(''), busy = ref(false), error = ref('')
async function enter() {
  if (!code.value.trim()) { open.value = false; emit('signIn', { mode: 'member' }); return }
  busy.value = true; error.value = ''
  try { const r = await $fetch<any>('/api/public/access/verify', { method: 'POST', body: { code: code.value } }); open.value = false; emit('signIn', { mode: 'referral', grantToken: r.grant_token }) }
  catch (e: any) { error.value = e?.data?.message || e?.message || 'This referral could not be verified.' }
  finally { busy.value = false }
}
const stages = [
  ['01','Understand','Madeus reads the portfolio context across companies, customers, code, people, policy, spend, and dependencies.'],
  ['02','Compose','The strongest models, agents, connected tools, and specialists assemble automatically around the outcome.'],
